 based on the following priority:\n *   1. Base URLs set via HttpOptions.\n *   2. Base URLs set via the latest call to setDefaultBaseUrls.\n *   3. Base URLs set via environment variables.\n */\nexport function getBaseUrl(\n  httpOptions: HttpOptions | undefined,\n  vertexai: boolean | undefined,\n  vertexBaseUrlFromEnv: string | undefined,\n  geminiBaseUrlFromEnv: string | undefined,\n): string | undefined {\n  if (!httpOptions?.baseUrl) {\n    const defaultBaseUrls = getDefaultBaseUrls();\n    if (vertexai) {\n      return defaultBaseUrls.vertexUrl ?? vertexBaseUrlFromEnv;\n    } else {\n      return defaultBaseUrls.geminiUrl ?? geminiBaseUrlFromEnv;\n    }\n  }\n\n  return httpOptions.baseUrl;\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n * SPDX-License-Identifier: Apache-2.0\n */\n\nexport class BaseModule {}\n\nexport function formatMap(\n  templateString: string,\n  valueMap: Record<string, unknown>,\n): string {\n  // Use a regular expression to find all placeholders in the template string\n  const regex = /\\{([^}]+)\\}/g;\n\n  // Replace each placeholder with its corresponding value from the valueMap\n  return templateString.replace(regex, (match, key) => {\n    if (Object.prototype.hasOwnProperty.call(valueMap, key)) {\n      const value = valueMap[key];\n      // Convert the value to a string if it's not a string already\n      return value !== undefined && value !== null ? String(value) : '';\n    } else {\n      // Handle missing keys\n      throw new Error(`Key '${key}' not found in valueMap.`);\n    }\n  });\n}\n\nexport function setValueByPath(\n  data: Record<string, unknown>,\n  keys: string[],\n  value: unknown,\n): void {\n  for (let i = 0; i < keys.length - 1; i++) {\n    const key = keys[i];\n\n    if (key.endsWith('[]')) {\n      const keyName = key.slice(0, -2);\n      if (!(keyName in data)) {\n        if (Array.isArray(value)) {\n          data[keyName] = Array.from({length: value.length}, () => ({}));\n        } else {\n          throw new Error(`Value must be a list given an array path ${key}`);\n        }\n      }\n\n      if (Array.isArray(data[keyName])) {\n        const arrayData = data[keyName] as Array<unknown>;\n\n        if (Array.isArray(value)) {\n          for (let j = 0; j < arrayData.length; j++) {\n            const entry = arrayData[j] as Record<string, unknown>;\n            setValueByPath(entry, keys.slice(i + 1), value[j]);\n          }\n        } else {\n          for (const d of arrayData) {\n            setValueByPath(\n              d as Record<string, unknown>,\n              keys.slice(i + 1),\n              value,\n            );\n          }\n        }\n      }\n      return;\n    } else if (key.endsWith('[0]')) {\n      const keyName = key.slice(0, -3);\n      if (!(keyName in data)) {\n        data[keyName] = [{}];\n      }\n      const arrayData = (data as Record<string, unknown>)[keyName];\n      setValueByPath(\n        (arrayData as Array<Record<string, unknown>>)[0],\n        keys.slice(i + 1),\n        value,\n      );\n      return;\n    }\n\n    if (!data[key] || typeof data[key] !== 'object') {\n      data[key] = {};\n    }\n\n    data = data[key] as Record<string, unknown>;\n  }\n\n  const keyToSet = keys[keys.length - 1];\n  const existingData = data[keyToSet];\n\n  if (existingData !== undefined) {\n    if (\n      !value ||\n      (typeof value === 'object' && Object.keys(value).length === 0)\n    ) {\n      return;\n    }\n\n    if (value === existingData) {\n      return;\n    }\n\n    if (\n      typeof existingData === 'object' &&\n      typeof value === 'object' &&\n      existingData !== null &&\n      value !== null\n    ) {\n      Object.assign(existingData, value);\n    } else {\n      throw new Error(`Cannot set value for an existing key. Key: ${keyToSet}`);\n    }\n  } else {\n    if (\n      keyToSet === '_self' &&\n      typeof value === 'object' &&\n      value !== null &&\n      !Array.isArray(value)\n    ) {\n      const valueAsRecord = value as Record<string, unknown>;\n\n      Object.assign(data, valueAsRecord);\n    } else {\n      data[keyToSet] = value;\n    }\n  }\n}\n\nexport function getValueByPath(\n  data: unknown,\n  keys: string[],\n  defaultValue: unknown = undefined,\n): unknown {\n  try {\n    if (keys.length === 1 && keys[0] === '_self') {\n      return data;\n    }\n\n    for (let i = 0; i < keys.length; i++) {\n      if (typeof data !== 'object' || data === null) {\n        return defaultValue;\n      }\n\n      const key = keys[i];\n      if (key.endsWith('[]')) {\n        const keyName = key.slice(0, -2);\n        if (keyName in data) {\n          const arrayData = (data as Record<string, unknown>)[keyName];\n          if (!Array.isArray(arrayData)) {\n            return defaultValue;\n          }\n          return arrayData.map((d) =>\n            getValueByPath(d, keys.slice(i + 1), defaultValue),\n          );\n        } else {\n          return defaultValue;\n        }\n      } else {\n        data = (data as Record<string, unknown>)[key];\n      }\n    }\n\n    return data;\n  } catch (error) {\n    if (error instanceof TypeError) {\n      return defaultValue;\n    }\n    throw error;\n  }\n}\n\n/**\n * Moves values from source paths to destination paths.\n *\n * Examples:\n *   moveValueByPath(\n *     {'requests': [{'content': v1}, {'content': v2}]},\n *     {'requests[].*': 'requests[].request.*'}\n *   )\n *     -> {'requests': [{'request': {'content': v1}}, {'request': {'content': v2}}]}\n */\nexport function moveValueByPath(\n  data: unknown,\n  paths: Record<string, string>,\n): void {\n  for (const [sourcePath, destPath] of Object.entries(paths)) {\n    const sourceKeys = sourcePath.split('.');\n    const destKeys = destPath.split('.');\n\n    // Determine keys to exclude from wildcard to avoid cyclic references\n    const excludeKeys = new Set<string>();\n    let wildcardIdx = -1;\n    for (let i = 0; i < sourceKeys.length; i++) {\n      if (sourceKeys[i] === '*') {\n        wildcardIdx = i;\n        break;\n      }\n    }\n\n    if (wildcardIdx !== -1 && destKeys.length > wildcardIdx) {\n      // Extract the intermediate key between source and dest paths\n      // Example: source=['requests[]', '*'], dest=['requests[]', 'request', '*']\n      // We want to exclude 'request'\n      for (let i = wildcardIdx; i < destKeys.length; i++) {\n        const key = destKeys[i];\n        if (key !== '*' && !key.endsWith('[]') && !key.endsWith('[0]')) {\n          excludeKeys.add(key);\n        }\n      }\n    }\n\n    _moveValueRecursive(data, sourceKeys, destKeys, 0, excludeKeys);\n  }\n}\n\n/**\n * Recursively moves values from source path to destination path.\n */\nfunction _moveValueRecursive(\n  data: unknown,\n  sourceKeys: string[],\n  destKeys: string[],\n  keyIdx: number,\n  excludeKeys: Set<string>,\n): void {\n  if (keyIdx >= sourceKeys.length) {\n    return;\n  }\n\n  if (typeof data !== 'object' || data === null) {\n    return;\n  }\n\n  const key = sourceKeys[keyIdx];\n\n  if (key.endsWith('[]')) {\n    const keyName = key.slice(0, -2);\n    const dataRecord = data as Record<string, unknown>;\n    if (keyName in dataRecord && Array.isArray(dataRecord[keyName])) {\n      for (const item of dataRecord[keyName] as Array<unknown>) {\n        _moveValueRecursive(\n          item,\n          sourceKeys,\n          destKeys,\n          keyIdx + 1,\n          excludeKeys,\n        );\n      }\n    }\n  } else if (key === '*') {\n    // wildcard - move all fields\n    if (typeof data === 'object' && data !== null && !Array.isArray(data)) {\n      const dataRecord = data as Record<string, unknown>;\n      const keysToMove = Object.keys(dataRecord).filter(\n        (k) => !k.startsWith('_') && !excludeKeys.has(k),\n      );\n\n      const valuesToMove: Record<string, unknown> = {};\n      for (const k of keysToMove) {\n        valuesToMove[k] = dataRecord[k];\n      }\n\n      // Set values at destination\n      for (const [k, v] of Object.entries(valuesToMove)) {\n        const newDestKeys: string[] = [];\n        for (const dk of destKeys.slice(keyIdx)) {\n          if (dk === '*') {\n            newDestKeys.push(k);\n          } else {\n            newDestKeys.push(dk);\n          }\n        }\n        setValueByPath(dataRecord, newDestKeys, v);\n      }\n\n      for (const k of keysToMove) {\n        delete dataRecord[k];\n      }\n    }\n  } else {\n    // Navigate to next level\n    const dataRecord = data as Record<string, unknown>;\n    if (key in dataRecord) {\n      _moveValueRecursive(\n        dataRecord[key],\n        sourceKeys,\n        destKeys,\n        keyIdx + 1,\n        excludeKeys,\n      );\n    }\n  }\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n * SPDX-License-Identifier: Apache-2.0\n */\n\nexport function tBytes(fromBytes: string | unknown): string {\n  if (typeof fromBytes !== 'string') {\n    throw new Error('fromImageBytes must be a string');\n  }\n  // TODO(b/389133914): Remove dummy bytes converter.\n  return fromBytes;\n}\n","/**\n * @license\n * Copyright 2025 Google LLC\n * SPDX-License-Identifier: Apache-2.0\n */\n\n// Code generated by the Google Gen AI SDK generator DO NOT EDIT.\n\nimport * as t from '../_base_transformers.js';\nimport * as common from '../_common.js';\nimport type * as types from '../types.js';\n\nexport function fetchPredictOperationParametersToMldev(\n  fromObject: types.FetchPredictOperationParameters,\n): Record<string, unknown> {\n  const toObject: Record<string, unknown> = {};\n\n  if (common.getValueByPath(fromObject, ['operationName']) !== undefined) {\n    throw new Error('operationName parameter is not supported in Gemini API.');\n  }\n\n  if (common.getValueByPath(fromObject, ['resourceName']) !== undefined) {\n    throw new Error('resourceName parameter is not supported in Gemini API.');\n  }\n\n  if (common.getValueByPath(fromObject, ['config']) !== undefined) {\n    throw new Error('config parameter is not suppo